                  import sailpoint.tools.Util;
                  import sailpoint.object.Filter;
                  import sailpoint.object.Form;
                  import sailpoint.object.Field;

                  Field field = form.getField("contractorSupervisor");

                 
                  Filter managerFilter = Filter.eq("managerStatus",true);
                  Filter inactiveFilter = Filter.eq("inactive",false);

                  Filter finalFilter = Filter.and(inactiveFilter,managerFilter);


                  field.setFilterString(finalFilter.toString());
                  field.setSortable(true);
